+import Foundation
+import ServiceManagement
+import Sparkle
+
+protocol LaunchAtLoginControlling: Sendable {
+    var isEnabled: Bool { get }
+    func register() throws
+    func unregister() throws
+}
+
+struct AppServiceLaunchAtLoginController: LaunchAtLoginControlling {
+    var isEnabled: Bool {
+        SMAppService.mainApp.status == .enabled
+    }
+
+    func register() throws {
+        try SMAppService.mainApp.register()
+    }
+
+    func unregister() throws {
+        try SMAppService.mainApp.unregister()
+    }
+}
+
+@MainActor
+protocol UpdateDriver: AnyObject {
+    func checkForUpdates()
+}
+
+@MainActor
+protocol UpdateChecking: AnyObject {
+    func checkForUpdates()
+}
+
+@MainActor
+final class SparkleUpdateDriver: NSObject, UpdateDriver {
+    private lazy var updaterController = SPUStandardUpdaterController(
+        startingUpdater: true,
+        updaterDelegate: nil,
+        userDriverDelegate: nil
+    )
+
+    func checkForUpdates() {
+        updaterController.checkForUpdates(nil)
+    }
+}
+
+@MainActor
+final class LazyUpdateChecker: UpdateChecking {
+    private let makeDriver: () -> any UpdateDriver
+    private lazy var driver = makeDriver()
+
+    init(makeDriver: @escaping () -> any UpdateDriver = { SparkleUpdateDriver() }) {
+        self.makeDriver = makeDriver
+    }
+
+    func checkForUpdates() {
+        driver.checkForUpdates()
+    }
+}
+
+protocol BundleInfoProviding: Sendable {
+    func appVersion() -> String?
+}
+
+struct MainBundleInfoProvider: BundleInfoProviding {
+    private let bundle: Bundle
+
+    init(bundle: Bundle = .main) {
+        self.bundle = bundle
+    }
+
+    func appVersion() -> String? {
+        bundle.object(forInfoDictionaryKey: "CFBundleShortVersionString") as? String
+    }
+}
+
+protocol CleanupModelStateRefreshing: Sendable {
+    func refresh()
+}
+
+struct NoOpCleanupModelStateRefresher: CleanupModelStateRefreshing {
+    func refresh() {
+    }
+}
+
+protocol ApplicationTerminationCleaning: Sendable {
+    func cancelScreenCapturePrefetch()
+    func shutdownCleanupBackend()
+}
+
+struct NoOpApplicationTerminationCleaner: ApplicationTerminationCleaning {
+    func cancelScreenCapturePrefetch() {
+    }
+
+    func shutdownCleanupBackend() {
+    }
+}
+
+enum ApplicationTerminationCoordinator {
+    private final class CleanerBox: @unchecked Sendable {
+        var cleaner: any ApplicationTerminationCleaning
+
+        init(cleaner: any ApplicationTerminationCleaning) {
+            self.cleaner = cleaner
+        }
+    }
+
+    private static let lock = NSLock()
+    private static let cleanerBox = CleanerBox(cleaner: NoOpApplicationTerminationCleaner())
+
+    static func setCleaner(_ cleaner: any ApplicationTerminationCleaning) {
+        lock.lock()
+        cleanerBox.cleaner = cleaner
+        lock.unlock()
+    }
+
+    static func handleWillTerminate() {
+        lock.lock()
+        let cleaner = cleanerBox.cleaner
+        lock.unlock()
+        cleaner.cancelScreenCapturePrefetch()
+        cleaner.shutdownCleanupBackend()
+    }
+}

