+}
+
+@MainActor
+final class OnboardingWindowManager: NSObject, OnboardingWindowManaging, NSWindowDelegate {
+    var onContinueToApp: ((Bool) -> Void)?
+
+    private var window: NSWindow?
+
+    var currentWindow: NSWindow? {
+        window
+    }
+
+    func show() {
+        NSApp.setActivationPolicy(.regular)
+
+        if let window {
+            window.makeKeyAndOrderFront(nil)
+            NSApp.activate(ignoringOtherApps: true)
+            return
+        }
+
+        let window = makeWindow()
+        self.window = window
+        window.makeKeyAndOrderFront(nil)
+        NSApp.activate(ignoringOtherApps: true)
+    }
+
+    func windowWillClose(_ notification: Notification) {
+        window = nil
+    }
+
+    func finishOnboarding(permissionsAlreadyAcquired: Bool) {
+        let window = self.window
+        self.window = nil
+        window?.close()
+        onContinueToApp?(permissionsAlreadyAcquired)
+    }
+
+    private func makeWindow() -> NSWindow {
+        let window = NSWindow(
+            contentRect: NSRect(x: 0, y: 0, width: 480, height: 620),
+            styleMask: [.titled, .closable],
+            backing: .buffered,
+            defer: false
+        )
+        window.title = "Ghost Pepper"
+        window.isReleasedWhenClosed = false
+        window.delegate = self
+        window.contentViewController = NSHostingController(
+            rootView: OnboardingShellView { [weak self] permissionsAlreadyAcquired in
+                self?.finishOnboarding(permissionsAlreadyAcquired: permissionsAlreadyAcquired)
+            }
+        )
+        return window
+    }
+}
